In the recipe, capture the worktree dir and branch name early, then wrap the provisioning steps:
```makefile
worktree:
	@test -n "$(name)" || { echo 'Usage: make worktree name=<branch> [dir=<path>]'; exit 1; }
	$(eval _dir := $(or $(dir),../$(name)))
	git fetch origin
	git worktree add $(_dir) -b $(name) origin/main || exit 1
	cd $(_dir) && python3 -m venv .venv && $(MAKE) install || \
	  { git worktree remove --force $(_dir); git branch -D $(name); echo 'Provisioning failed; worktree removed.'; exit 1; }
	@echo 'Activate with: cd $(_dir) && source .venv/bin/activate'
```
